import { Component, OnInit } from '@angular/core';
import { forkJoin, of, switchMap } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { ResumeAnalysis } from '../../core/models/analysis.model';
import { JobMatch } from '../../core/models/job.model';
import { ResumeResponse } from '../../core/models/resume.model';
import { User } from '../../core/models/user.model';
import { AuthService } from '../../core/services/auth.service';
import { JobService } from '../../core/services/job.service';
import { ResumeService } from '../../core/services/resume.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html'
})
export class DashboardComponent implements OnInit {
  loading = true;
  user: User | null = null;
  resumes: ResumeResponse[] = [];
  latestResume: ResumeResponse | null = null;
  latestAnalysis: ResumeAnalysis | null = null;
  latestMatches: JobMatch[] = [];

  constructor(
    private readonly authService: AuthService,
    private readonly resumeService: ResumeService,
    private readonly jobService: JobService
  ) {
  }

  ngOnInit(): void {
    this.loadDashboard();
  }

  private loadDashboard(): void {
    this.loading = true;
    this.authService.getProfile().pipe(
      switchMap((user) => {
        this.user = user;
        return this.resumeService.getResumes();
      }),
      switchMap((resumes) => {
        this.resumes = resumes;
        this.latestResume = resumes[0] ?? null;

        if (!this.latestResume) {
          return of({ analysis: null, matches: [] as JobMatch[] });
        }

        return forkJoin({
          analysis: this.resumeService.getResumeAnalysis(this.latestResume.id).pipe(
            catchError(() => of(null))
          ),
          matches: this.jobService.getJobMatches(this.latestResume.id).pipe(
            catchError(() => of([]))
          )
        });
      })
    ).subscribe({
      next: ({ analysis, matches }) => {
        this.latestAnalysis = analysis;
        this.latestMatches = matches;
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }
}
<app-loader *ngIf="loading" message="Loading your dashboard"></app-loader>

<div *ngIf="!loading" class="space-y-6">
  <section class="grid gap-5 xl:grid-cols-[1.2fr_0.8fr]">
    <div class="glass-panel p-6 md:p-8">
      <p class="text-sm font-semibold uppercase tracking-[0.3em] text-poppy">Dashboard</p>
      <h2 class="section-title mt-4 max-w-2xl text-4xl leading-tight">
        {{ user?.name || 'Candidate' }}, focus on one polished resume flow first.
      </h2>
      <p class="mt-4 max-w-2xl text-base leading-7 text-ink/65">
        Upload one PDF, trigger analysis, improve the strongest weak points, and move directly into matched fresher roles.
      </p>
      <div class="mt-8 flex flex-wrap gap-3">
        <a routerLink="/resume/upload" class="btn-primary">Upload Resume</a>
        <a *ngIf="latestResume" [routerLink]="['/resume', latestResume.id, 'analysis']" class="btn-secondary">View Latest Analysis</a>
      </div>
    </div>

    <app-score-card [score]="latestAnalysis?.atsScore ?? 0"></app-score-card>
  </section>

  <section class="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
    <div class="glass-panel p-5">
      <p class="text-sm text-ink/55">Total resumes uploaded</p>
      <p class="mt-3 text-4xl font-extrabold text-ink">{{ resumes.length }}</p>
    </div>
    <div class="glass-panel p-5">
      <p class="text-sm text-ink/55">Last ATS score</p>
      <p class="mt-3 text-4xl font-extrabold text-pine">{{ latestAnalysis?.atsScore ?? '--' }}</p>
    </div>
    <div class="glass-panel p-5">
      <p class="text-sm text-ink/55">Improvement status</p>
      <p class="mt-3 text-2xl font-extrabold text-ink">{{ latestAnalysis ? 'Suggestions ready' : 'Needs analysis' }}</p>
    </div>
    <div class="glass-panel p-5">
      <p class="text-sm text-ink/55">Suggested jobs count</p>
      <p class="mt-3 text-4xl font-extrabold text-brass">{{ latestMatches.length }}</p>
    </div>
  </section>

  <section class="grid gap-5 xl:grid-cols-[0.95fr_1.05fr]">
    <div class="glass-panel p-6">
      <div class="flex items-center justify-between">
        <div>
          <p class="text-sm font-semibold uppercase tracking-[0.28em] text-ink/45">Latest resume</p>
          <h3 class="section-title mt-2 text-3xl">{{ latestResume?.fileName || 'No resume uploaded yet' }}</h3>
        </div>
        <a *ngIf="latestResume" [routerLink]="['/resume', latestResume.id]" class="btn-secondary px-4 py-2 text-sm">Open</a>
      </div>

      <div class="mt-6 space-y-4 text-sm text-ink/70" *ngIf="latestResume; else noResume">
        <p><span class="font-semibold text-ink">Status:</span> {{ latestResume.status }}</p>
        <p><span class="font-semibold text-ink">Uploaded:</span> {{ latestResume.createdAt | date:'medium' }}</p>
        <p><span class="font-semibold text-ink">Preview:</span> {{ latestResume.extractedText | slice:0:220 }}...</p>
      </div>

      <ng-template #noResume>
        <p class="mt-6 text-sm leading-7 text-ink/65">
          Your dashboard becomes useful only after the first PDF upload. Start there before spending time on pricing or plan logic.
        </p>
      </ng-template>
    </div>

    <div class="glass-panel p-6">
      <p class="text-sm font-semibold uppercase tracking-[0.28em] text-ink/45">Recent improvement focus</p>
      <h3 class="section-title mt-2 text-3xl">What to fix next</h3>

      <div class="mt-6 grid gap-4 md:grid-cols-2">
        <div class="rounded-3xl bg-poppy/8 p-5">
          <p class="font-semibold text-poppy">Weaknesses</p>
          <ul class="mt-3 space-y-2 text-sm text-ink/70">
            <li *ngFor="let item of latestAnalysis?.weaknesses || ['Run analysis to generate targeted weaknesses.']">{{ item }}</li>
          </ul>
        </div>
        <div class="rounded-3xl bg-pine/8 p-5">
          <p class="font-semibold text-pine">Matched skills</p>
          <ul class="mt-3 space-y-2 text-sm text-ink/70">
            <li *ngFor="let job of latestMatches | slice:0:3">{{ job.title }}: {{ job.matchedSkills | joinList }}</li>
            <li *ngIf="latestMatches.length === 0">Run analysis and job matching to see skill alignment.</li>
          </ul>
        </div>
      </div>
    </div>
  </section>
</div>
